548	                       << tileShape.size();
549	
550	  if (dimMap.size() != tileShape.size())
551	    return emitError() << "expected dim_map to map exactly all "
552	                       << tileShape.size() << " dimensions of the tile, got "
553	                       << dimMap.size() << " mappings";
554	
555	  if (any_of(tileShape, [](int32_t dim) { return dim <= 0; }))
556	    return emitError()
557	           << "tile shape dimensions must have positive length but got ["
558	           << tileShape << "]";
559	
560	  if (any_of(tileShape, [](int32_t dim) { return (dim & (dim - 1)) != 0; }))
561	    return emitError()
562	           << "tile shape dimensions must have power of two length but got ["
563	           << tileShape << "]";
