568	    if (tensorViewDim < 0)
569	      return emitError() << "target dimension must not be negative, got "
570	                         << tensorViewDim;
571	
572	    if (static_cast<uint32_t>(tensorViewDim) >= tensorView.getShape().size())
573	      return emitError()
574	             << "target dimension is outside of tensor view dimensions, "
575	                "expected strictly less than "
576	             << tensorView.getShape().size() << ", got " << tensorViewDim;
577	
578	    if (usedTensorViewDim[tensorViewDim].has_value())
579	      return emitError() << "target dimension " << tensorViewDim
580	                         << " mapped at least twice (for tile dimensions "
581	                         << usedTensorViewDim[tensorViewDim].value() << " and "
